func messageContainerClass(message domain.Message) string {
	if message.Visibility == domain.VisibilityInternal {
		return "bg-amber-50 border-amber-200"
	}
	if message.AuthorRole == domain.ActorStaff {
		return "bg-blue-50 border-blue-100"
	}

	return "bg-white border-gray-200"
}

func messageAvatarClass(message domain.Message) string {
	if message.Visibility == domain.VisibilityInternal {
		return "bg-amber-200 text-amber-900"
	}
	if message.AuthorRole == domain.ActorStaff {
		return "bg-blue-600 text-white"
	}

	return "bg-gray-200 text-gray-700"
}

func messageAuthorLabel(message domain.Message) string {
	if message.AuthorRole == domain.ActorStaff {
		return "Staff"
	}

	return "You"
}

func authorInitial(message domain.Message) string {
	if message.AuthorRole == domain.ActorStaff {
		return "S"
	}

	return "P"
}

func composerPostURL(ticket domain.Ticket, _ bool) string {
	return fmt.Sprintf("/tickets/%d/reply", ticket.ID)
}

